#include <iostream>
#include <unordered_map>
#include <string>
#include <memory>
#include <chrono>

class Session {
public:
    std::string data;
    std::chrono::system_clock::time_point expiryTime;

    Session(const std::string& d, int duration) : data(d) {
        expiryTime = std::chrono::system_clock::now() + std::chrono::seconds(duration);
    }

    bool isValid() const {
        return std::chrono::system_clock::now() < expiryTime;
    }
};

class SessionCache {
private:
    std::unordered_map<std::string, std::shared_ptr<Session>> cache;

public:
    void createSession(const std::string& sessionId, const std::string& data, int duration) {
        auto session = std::make_shared<Session>(data, duration);
        cache[sessionId] = session;
    }

    std::string accessSession(const std::string& sessionId) {
        auto it = cache.find(sessionId);
        if (it != cache.end()) {
            if (it->second->isValid()) {
                return it->second->data;
            } else {
                invalidateSession(sessionId);
            }
        }
        return "";
    }

    void invalidateSession(const std::string& sessionId) {
        auto it = cache.find(sessionId);
        if (it != cache.end()) {
            it->second.reset();
            // Optionally, remove the entry from the map to free memory
            // cache.erase(it);
        }
    }
};

